const binaryData = $input.first().json.video;
let videoSize = 0;

// Jika data adalah base64 string
if (typeof binaryData === 'string') {
  // Hitung ukuran asli dari base64
  const base64String = binaryData;
  const padding = (base64String.match(/=/g) || []).length;
  videoSize = Math.floor((base64String.length * 3) / 4) - padding;
} 
// Jika data adalah Buffer
else if (Buffer.isBuffer(binaryData)) {
  videoSize = binaryData.length;
}

return { videoSize };

